#include <stdio.h>
int main(void) {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long ans;
        switch (N % 4) {
            case 0:
            case 3:
                ans = 3;
                break;
            case 1:
                ans = N + 2;
                break;
            case 2:
                ans = N - 1;
                break;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

