import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        r = N % 4
        if r == 0 or r == 3:
            out.append('3')
        elif r == 1:
            out.append(str(N + 2))
        else:  # r == 2
            out.append(str(N - 1))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

